import{_ as e,o as a,c as r,ag as n}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"Batting Lineup Builder","description":"","frontmatter":{},"headers":[],"relativePath":"lineup/batting.md","filePath":"lineup/batting.md"}'),i={name:"lineup/batting.md"};function o(d,t,s,l,h,p){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="batting-lineup-builder" tabindex="-1">Batting Lineup Builder <a class="header-anchor" href="#batting-lineup-builder" aria-label="Permalink to &quot;Batting Lineup Builder&quot;">​</a></h1><p>The batting lineup builder suggests batting order based on OBP, power, and contact metrics from your season data.</p><h2 id="how-the-order-is-built" tabindex="-1">How the Order Is Built <a class="header-anchor" href="#how-the-order-is-built" aria-label="Permalink to &quot;How the Order Is Built&quot;">​</a></h2><p>The algorithm uses a traditional lineup construction approach:</p><table tabindex="0"><thead><tr><th>Spot</th><th>Priority Metric</th><th>Logic</th></tr></thead><tbody><tr><td>1st</td><td>OBP</td><td>Get on base most consistently</td></tr><tr><td>2nd</td><td>Contact + Speed</td><td>Make contact, move runners</td></tr><tr><td>3rd</td><td>BA + Power</td><td>Best all-around hitter</td></tr><tr><td>4th</td><td>Power (SLG)</td><td>Drive in runs</td></tr><tr><td>5th</td><td>Power</td><td>Second power bat</td></tr><tr><td>6th–7th</td><td>BA</td><td>Solid contact hitters</td></tr><tr><td>8th–9th</td><td>Remaining</td><td>Lower-data players</td></tr></tbody></table><h2 id="reordering-the-lineup" tabindex="-1">Reordering the Lineup <a class="header-anchor" href="#reordering-the-lineup" aria-label="Permalink to &quot;Reordering the Lineup&quot;">​</a></h2><p>Drag and drop any player card to change their spot in the order. Changes are reflected immediately in the stat comparison panel.</p><h2 id="stat-comparison-panel" tabindex="-1">Stat Comparison Panel <a class="header-anchor" href="#stat-comparison-panel" aria-label="Permalink to &quot;Stat Comparison Panel&quot;">​</a></h2><p>The panel on the right (or bottom on mobile) shows key metrics for every player in the lineup:</p><ul><li>BA (Batting Average)</li><li>OBP (On-Base Percentage)</li><li>SLG (Slugging)</li><li>HR, RBI</li><li>K% and BB%</li><li>Recent form sparkline</li></ul><p>Use this panel to evaluate your drag-and-drop changes against the data.</p><h2 id="sparklines" tabindex="-1">Sparklines <a class="header-anchor" href="#sparklines" aria-label="Permalink to &quot;Sparklines&quot;">​</a></h2><p>Each player card shows a mini sparkline of their last 10 at-bats. This gives you a quick read on current hot/cold streaks independent of season totals. A player hitting .280 for the season but going 0-for-8 in their last two games may not be the right choice for the 3 hole today.</p><h2 id="saving-a-lineup" tabindex="-1">Saving a Lineup <a class="header-anchor" href="#saving-a-lineup" aria-label="Permalink to &quot;Saving a Lineup&quot;">​</a></h2><p>Tap <strong>Save Lineup</strong> to save the current configuration. Name the lineup (e.g. &quot;Opening Day&quot; or &quot;Vs RHP&quot;) for reference. Saved lineups appear in the lineup history and can be recalled for future games.</p><h2 id="game-day-share" tabindex="-1">Game Day Share <a class="header-anchor" href="#game-day-share" aria-label="Permalink to &quot;Game Day Share&quot;">​</a></h2><p>Tap <strong>Share</strong> to send the batting lineup via text, email, or any messaging app using the Web Share API. The shared format includes player names and jersey numbers in batting order — easy to send to parents or post in the dugout.</p>',17)])])}const g=e(i,[["render",o]]);export{c as __pageData,g as default};
